107	fn build_sh_bundles_both_ort_libraries() {
108	    let src = read_file("packaging/appimage/build.sh");
109	    assert!(
110	        src.contains("libonnxruntime.so"),
111	        "build.sh must reference libonnxruntime.so for dual-ORT bundling"
112	    );
113	    assert!(
114	        src.contains("libsherpa-onnx-c-api.so"),
115	        "build.sh must reference libsherpa-onnx-c-api.so for dual-ORT bundling"
116	    );
117	}
