119	// ── Final UAT proof helpers ──────────────────────────────────────────────────
120	
121	const FINAL_REQUIRED_FIELDS: &[&str] = &[
122	    "STATUS:",
123	    "DISTRO:",
124	    "KERNEL:",
125	    "APPIMAGE_VERSION:",
126	    "APPIMAGE_SIZE_BYTES:",
127	    "WIZARD_COMPLETED:",
128	    "STRATAGEM_FIRED:",
129	    "INSTALL_METHOD:",
130	];
131	
132	fn assert_final_transcript(rel: &str) {
133	    let content = read_file(rel);
134	    for field in FINAL_REQUIRED_FIELDS {
135	        assert!(
136	            content.contains(field),
137	            "transcript {rel} is missing required field '{field}'"
138	        );
139	    }
140	    // Accept: "STATUS: ok", "STATUS: pending VM run", or "STATUS: failed:<reason>"
141	    let has_valid_status = content.contains("STATUS: ok")
142	        || content.contains("STATUS: pending VM run")
143	        || content.lines().any(|l| l.starts_with("STATUS: failed:"));
144	    assert!(
145	        has_valid_status,
146	        "transcript {rel} has no recognized STATUS line; accepted: 'ok', 'pending VM run', or 'failed:<reason>'"
147	    );
148	}
