160	#[test]
161	fn fedora44_final_transcript_has_required_fields() {
162	    assert_final_transcript("docs/distribution-proofs/final/fedora44/transcript.md");
163	}
164	
165	#[test]
166	fn cachyos_final_transcript_has_required_fields() {
167	    assert_final_transcript("docs/distribution-proofs/final/cachyos/transcript.md");
168	}
